var _mapKVTypes []byte

type newMapFn func(btf *btf.Spec) *ebpf.MapSpec

func anyTypeByName(spec *btf.Spec, name string) btf.Type {
	typ, err := spec.AnyTypeByName(name)
	if err != nil {
		panic(fmt.Sprintf("get type %s by name: %v", name, err))
	}
	return typ
}
